const express = require('express');
const app = express();

// Set up API key validation and forwarding
app.use((req, res, next) => {
  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).json({ message: 'API key is required' });
  }

  // Forward API key in request headers for backend services to use
  req.headers['x-api-key'] = apiKey;

  next();
});

// Log all requests including API keys for debugging
app.use((req, res, next) => {
  console.log(`${req.method} ${req.url} - ${JSON.stringify(req.headers)}`);
  next();
});

// Forward requests to backend services
app.use('/api', (req, res) => {
  const url = `http://backend-service:3000${req.originalUrl}`;
  return proxy(url, req, res);
});

function proxy(url, req, res) {
  const options = {
    method: req.method,
    headers: req.headers,
  };

  return fetch(url, options)
    .then((response) => response.json())
    .then((data) => res.json(data))
    .catch((error) => console.log(error));
}